-- 7-day retention: caches and outputs
DELETE FROM gda_prompt_architect_memory WHERE created_at < NOW() - INTERVAL '7 days';
DELETE FROM gda_competitor_cache WHERE created_at < NOW() - INTERVAL '7 days';
DELETE FROM gda_dashboard_intel_cache WHERE created_at < NOW() - INTERVAL '7 days';
DELETE FROM govtribe_cache WHERE cached_at < NOW() - INTERVAL '7 days';

-- 30-day retention: logs and history
DELETE FROM gda_intelligence_log WHERE "timestamp" < NOW() - INTERVAL '30 days';
DELETE FROM gda_action_history WHERE expires_at < NOW();

-- Count what remains
SELECT
  'retention_complete' as status,
  (SELECT COUNT(*) FROM gda_prompt_architect_memory) as prompt_arch,
  (SELECT COUNT(*) FROM gda_competitor_cache) as comp_cache,
  (SELECT COUNT(*) FROM daily_trends) as trends,
  (SELECT COUNT(*) FROM gda_intelligence_log) as intel_log,
  (SELECT COUNT(*) FROM gda_action_history) as action_history;

